mapper.select:
select #{incomePeriod, jdbcType = VARCHAR} as income_period, sum(spssi.overtime_pay_time) as overtime_pay_time, sum(spssi.holiday_overtime_pay_time) as holiday_overtime_pay_time, sum(spssi.rest_overtime_pay_time) as rest_overtime_pay_time, sum(spssi.overtime_pay) as overtime_pay, sum(spssi.holiday_overtime_pay) as holiday_overtime_pay, sum(spssi.rest_overtime_pay) as rest_overtime_pay, sum(spssi.safety_accumulation_award) as safety_accumulation_award, sum(spssi.high_temperature_subsidy) as high_temperature_subsidy, sum(spssi.transportation_allowance) as transportation_allowance, sum(spssi.deduct_hydropower_house) as deduct_hydropower_house, sum(spssi.allowance_deduction) as allowance_deduction, sum(spssi.deduct_other) as deduct_other, sum(spssi.deduct_income_tax) as deduct_income_tax from swm_post_skill_salary_interface spssi where spssi.income_period = #{incomePeriod, jdbcType = VARCHAR} and spssi.data_status = 'T'
and spssi.work_card in (
right(replicate('0',6) + convert(varchar(6),#{item}),6)
)
and spssi.group_id in (
#{groupId}
)
